import React, { useEffect, useState } from "react";
import { Table, Button, Space, Input } from "antd";
import {
  Edit3,
  Trash2,
  Search,
  Plus,
  Hash,
  Activity,
  ShieldCheck,
} from "lucide-react";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";
import { deleteTag, getTags, resetState } from "../features/tags/tagsSlice";
import CustomModal from "../components/CustomModal";

const Taglist = () => {
  const [open, setOpen] = useState(false);
  const [pCatId, setpCatId] = useState("");
  const [searchText, setSearchText] = useState("");

  const showModal = (e) => {
    setOpen(true);
    setpCatId(e);
  };

  const hideModal = () => {
    setOpen(false);
  };

  const dispatch = useDispatch();
  useEffect(() => {
    dispatch(resetState());
    dispatch(getTags());
  }, [dispatch]);

  const tagState = useSelector((state) => state.tag.tags);

  const columns = [
    {
      title: "#",
      dataIndex: "key",
      width: 80,
      render: (text) => (
        <span className="font-mono text-[10px] font-black text-slate-400 bg-slate-50 px-2 py-1 rounded-md">
          TAG-{text}
        </span>
      ),
    },
    {
      title: "TAG NAME",
      dataIndex: "name",
      render: (text) => (
        <span className="font-black text-slate-900 tracking-tight uppercase text-xs">
          {text}
        </span>
      ),
      sorter: (a, b) => a.name.length - b.name.length,
    },
    {
      title: "ACTIONS",
      dataIndex: "action",
      render: (_, record) => (
        <Space size="middle">
          <Link to={`../tag/${record._id}`}>
            <Button
              type="text"
              icon={<Edit3 size={16} />}
              className="text-slate-400 hover:text-blue-600 rounded-xl"
            />
          </Link>
          <Button
            type="text"
            danger
            icon={<Trash2 size={16} />}
            onClick={() => showModal(record._id)}
            className="rounded-xl"
          />
        </Space>
      ),
    },
  ];

  const data1 =
    tagState
      ?.filter(
        (t) =>
          !searchText ||
          t.title.toLowerCase().includes(searchText.toLowerCase()),
      )
      .map((tag, i) => ({
        key: i + 1,
        _id: tag._id,
        name: tag.title,
      })) || [];

  const deleteCategory = (e) => {
    dispatch(deleteTag(e));
    toast.success("Tag Deleted Successfully");
    setOpen(false);
    setTimeout(() => {
      dispatch(getTags());
    }, 500);
  };

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-1000">
      {/* Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 bg-white/40 p-1 rounded-[32px] border border-white/60">
        <div className="pl-8 py-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-10 h-10 bg-[#257CB7] rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-500/20">
              <Hash size={20} />
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tighter">
              Tag Registry
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <span className="flex items-center gap-2 text-[10px] font-black text-blue-600 bg-blue-50 border border-blue-100 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
              <ShieldCheck size={12} /> {data1.length} Tags
            </span>
            <span className="flex items-center gap-2 text-[10px] font-black text-emerald-600 bg-emerald-50 border border-emerald-100 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
              <Activity size={12} /> System Active
            </span>
          </div>
        </div>
        <div className="flex items-center gap-3 pr-4">
          <div className="relative">
            <Search
              className="absolute top-1/2 left-4 -translate-y-1/2 text-slate-300"
              size={16}
            />
            <Input
              placeholder="Search tags..."
              className="pl-11 rounded-2xl border-slate-100 w-64 h-11 font-medium text-xs"
              onChange={(e) => setSearchText(e.target.value)}
            />
          </div>
          <Link to="../tags">
            <Button
              type="primary"
              size="large"
              icon={<Plus size={16} />}
              className="bg-[#257CB7] rounded-2xl h-11 font-black text-[10px] uppercase tracking-widest shadow-xl shadow-blue-500/20 border-none flex items-center gap-2"
            >
              Add Tag
            </Button>
          </Link>
        </div>
      </div>

      {/* Table Card */}
      <div className="enterprise-card bg-white p-4 border-none shadow-2xl shadow-slate-200/40">
        <Table
          columns={columns}
          dataSource={data1}
          pagination={{ pageSize: 12 }}
          className="enterprise-table"
        />
      </div>

      <CustomModal
        hideModal={hideModal}
        open={open}
        performAction={() => deleteCategory(pCatId)}
        title="Confirm Tag Deletion"
        content="This will remove the tag permanently. Products using this tag may lose their association."
      />
    </div>
  );
};

export default Taglist;
